_patient_demographics AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource, CAST(fhirpath_date(r.resource, 'birthDate') AS DATE) AS birth_date FROM resources r WHERE r.resourceType = 'Patient'
),
"Observation: Emergency Department Evaluation" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource FROM resources r WHERE r.resourceType = 'Observation' AND in_valueset(r.resource, 'code', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1111.163')
),
"Encounter: Emergency Department Evaluation and Management Visit" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource, fhirpath_text(r.resource, 'status') AS status FROM resources r WHERE r.resourceType = 'Encounter' AND in_valueset(r.resource, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.464.1003.101.12.1010')
),
"ServiceRequest: Encounter Inpatient" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource, fhirpath_text(r.resource, 'status') AS status FROM resources r WHERE r.resourceType = 'ServiceRequest' AND in_valueset(r.resource, 'code', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.666.5.307') AND (json_extract(r.resource, '$.meta.profile') IS NULL OR NOT list_contains(from_json(json_extract(r.resource, '$.meta.profile'), '["VARCHAR"]'), 'http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-servicenotrequested'))
),
"ServiceRequest: Decision to Admit to Hospital Inpatient" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource, fhirpath_text(r.resource, 'status') AS status FROM resources r WHERE r.resourceType = 'ServiceRequest' AND in_valueset(r.resource, 'code', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.294') AND (json_extract(r.resource, '$.meta.profile') IS NULL OR NOT list_contains(from_json(json_extract(r.resource, '$.meta.profile'), '["VARCHAR"]'), 'http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-servicenotrequested'))
),
"Encounter: Observation Services" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource FROM resources r WHERE r.resourceType = 'Encounter' AND in_valueset(r.resource, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1111.143')
),
"ServiceRequest: Patient bed assigned (finding)" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource, fhirpath_text(r.resource, 'status') AS status FROM resources r WHERE r.resourceType = 'ServiceRequest' AND fhirpath_bool(r.resource, 'code.coding.where(system=''http://snomed.info/sct'' and code=''5751000175101'').exists()') AND (json_extract(r.resource, '$.meta.profile') IS NULL OR NOT list_contains(from_json(json_extract(r.resource, '$.meta.profile'), '["VARCHAR"]'), 'http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-servicenotrequested'))
),
"Encounter: Triage" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource, fhirpath_text(r.resource, 'status') AS status FROM resources r WHERE r.resourceType = 'Encounter' AND in_valueset(r.resource, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1046.279')
),
"Location" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource FROM resources r WHERE r.resourceType = 'Location'
),
"Encounter: Encounter Inpatient" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource, fhirpath_text(r.resource, 'status') AS status FROM resources r WHERE r.resourceType = 'Encounter' AND in_valueset(r.resource, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.666.5.307')
),
"Coverage: Payer Type" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource, fhirpath_text(r.resource, 'type') AS "type" FROM resources r WHERE r.resourceType = 'Coverage' AND in_valueset(r.resource, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.114222.4.11.3591')
),
"CQMCommon.Inpatient Encounter" AS (
SELECT * FROM "Encounter: Encounter Inpatient" AS EncounterInpatient WHERE EncounterInpatient.status = 'finished' AND CAST(intervalEnd(fhirpath_text(EncounterInpatient.resource, 'period')) AS DATE) BETWEEN CAST(intervalStart(intervalFromBounds(CAST(CAST('2027-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2027-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE) AND COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2027-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2027-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST(intervalStart(intervalFromBounds(CAST(CAST('2027-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2027-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE))
),
"SDE.SDE Ethnicity" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-ethnicity'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_E -> json_object('codes', "Distinct"(list_concat([fhirpath_text(_lt_E, 'ombCategory')], fhirpath_text(_lt_E, 'detailed'))), 'display', fhirpath_text(_lt_E, 'text'))) AS resource FROM _patients AS p
),
"SDE.SDE Payer" AS (
SELECT _inner.patient_id, _inner._resource_data AS resource FROM (SELECT patient_id, json_object('code', Payer.type, 'period', fhirpath_text(Payer.resource, 'period')) AS _resource_data FROM "Coverage: Payer Type" AS Payer) AS _inner
),
"SDE.SDE Race" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-race'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_R -> json_object('codes', CASE WHEN fhirpath_text(_lt_R, 'ombCategory') IS NOT NULL  AND fhirpath_text(_lt_R, 'detailed') IS NOT NULL  THEN "Distinct"(jsonConcat(fhirpath_text(_lt_R, 'ombCategory'), fhirpath_text(_lt_R, 'detailed'))) ELSE NULL END, 'display', fhirpath_text(_lt_R, 'text'))) AS resource FROM _patients AS p
),
"SDE.SDE Sex" AS (
SELECT p.patient_id, (SELECT CASE WHEN fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex'').valueCode') = '248153007' THEN 'http://snomed.info/sct|248153007' WHEN fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex'').valueCode') = '248152002' THEN 'http://snomed.info/sct|248152002' ELSE NULL END) AS value FROM _patients AS p
),
"Assessment In ED" AS (
SELECT patient_id, resource FROM "Observation: Emergency Department Evaluation" UNION (SELECT patient_id, resource FROM "Observation: Emergency Department Evaluation" AS ObsInED WHERE in_valueset(ObsInED.resource, 'value', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1111.164'))
),
"ED Evaluation and Management" AS (
SELECT * FROM "Encounter: Emergency Department Evaluation and Management Visit" AS EDEvalManagementVisit WHERE CAST(intervalEnd(fhirpath_text(EDEvalManagementVisit.resource, 'period')) AS DATE) BETWEEN CAST(intervalStart(intervalFromBounds(CAST(CAST('2027-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2027-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE) AND COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2027-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2027-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST(intervalStart(intervalFromBounds(CAST(CAST('2027-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2027-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE)) AND EDEvalManagementVisit.status = 'finished'
),
"ED To Inpatient Order" AS (
SELECT * FROM "ServiceRequest: Decision to Admit to Hospital Inpatient" AS AdmitIPOrder WHERE array_contains(['active', 'completed'], AdmitIPOrder.status)
),
"ED Triage" AS (
SELECT * FROM "Encounter: Triage" AS EDTriage WHERE CAST(intervalEnd(fhirpath_text(EDTriage.resource, 'period')) AS DATE) BETWEEN CAST(intervalStart(intervalFromBounds(CAST(CAST('2027-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2027-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE) AND COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2027-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2027-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST(intervalStart(intervalFromBounds(CAST(CAST('2027-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2027-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE)) AND array_contains(['finished', 'triaged'], EDTriage.status)
),
"ED Triage Excluding Those Prior To ED Encounters" AS (
SELECT * FROM "ED Triage" AS EDTriageinMP WHERE NOT EXISTS (SELECT * FROM "ED Evaluation and Management" AS EDEvalManagementInMP WHERE (intervalOverlapsBefore(fhirpath_text(EDTriageinMP.resource, 'period'), fhirpath_text(EDEvalManagementInMP.resource, 'period')) OR intervalIncludes(fhirpath_text(EDEvalManagementInMP.resource, 'period'), fhirpath_text(EDTriageinMP.resource, 'period')) OR intervalIncludes(fhirpath_text(EDTriageinMP.resource, 'period'), fhirpath_text(EDEvalManagementInMP.resource, 'period')) OR CAST(intervalStart(fhirpath_text(EDEvalManagementInMP.resource, 'period')) AS TIMESTAMP) - INTERVAL '120 minute' <= CAST(intervalEnd(fhirpath_text(EDTriageinMP.resource, 'period')) AS TIMESTAMP) AND CAST(intervalEnd(fhirpath_text(EDTriageinMP.resource, 'period')) AS TIMESTAMP) < CAST(intervalStart(fhirpath_text(EDEvalManagementInMP.resource, 'period')) AS TIMESTAMP)) AND EDEvalManagementInMP.patient_id = EDTriageinMP.patient_id)
),
"Initial Population" AS (
(SELECT patient_id, resource FROM "ED Evaluation and Management") UNION (SELECT patient_id, resource FROM "ED Triage Excluding Those Prior To ED Encounters")
),
"Denominator" AS (
SELECT * FROM "Initial Population"
),
"ED Arrival Left Without Being Seen" AS (
SELECT * FROM "Denominator" AS EDEncounter WHERE fhirpath_bool(EDEncounter.resource, 'hospitalization.dischargeDisposition.coding.where(system=''http://snomed.info/sct'' and code=''21541000119102'').exists()')
),
"ED Encounter or Triage of Patients 18 Years and Older" AS (
SELECT * FROM "Denominator" AS EDEncounter WHERE EXTRACT(YEAR FROM CAST('2027-01-01T00:00:00.000' AS TIMESTAMP)) - EXTRACT(YEAR FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = EDEncounter.patient_id LIMIT 1)) - CASE WHEN EXTRACT(MONTH FROM CAST('2027-01-01T00:00:00.000' AS TIMESTAMP)) < EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = EDEncounter.patient_id LIMIT 1)) OR EXTRACT(MONTH FROM CAST('2027-01-01T00:00:00.000' AS TIMESTAMP)) = EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = EDEncounter.patient_id LIMIT 1)) AND EXTRACT(DAY FROM CAST('2027-01-01T00:00:00.000' AS TIMESTAMP)) < EXTRACT(DAY FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = EDEncounter.patient_id LIMIT 1)) THEN 1 ELSE 0 END >= 18
),
"Adult With Mental Health Diagnosis" AS (
SELECT * FROM "ED Encounter or Triage of Patients 18 Years and Older" AS AdultEDEncounters WHERE EXISTS (SELECT '1' FROM (SELECT patient_ref AS patient_id, resource FROM resources WHERE resourceType = 'Claim') AS _c WHERE _c.patient_id = AdultEDEncounters.patient_id AND fhirpath_text(_c.resource, 'status') = 'active' AND fhirpath_text(_c.resource, 'use') = 'claim' AND claim_principal_diagnosis(_c.resource, fhirpath_text(AdultEDEncounters.resource, 'id')) IS NOT NULL AND (in_valueset(claim_principal_diagnosis(_c.resource, fhirpath_text(AdultEDEncounters.resource, 'id')), 'diagnosisCodeableConcept', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1046.285') OR EXISTS (SELECT '1' FROM (SELECT patient_ref AS patient_id, resource FROM resources WHERE resourceType = 'Condition') AS _cond WHERE _cond.patient_id = AdultEDEncounters.patient_id AND in_valueset(_cond.resource, 'code', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1046.285') AND fhirpath_text(claim_principal_diagnosis(_c.resource, fhirpath_text(AdultEDEncounters.resource, 'id')), 'diagnosisReference.reference') LIKE '%/' || fhirpath_text(_cond.resource, 'id'))))
),
"Adult With No Mental Health Diagnosis" AS (
SELECT * FROM "ED Encounter or Triage of Patients 18 Years and Older" AS AdultEDEncounters WHERE NOT EXISTS (SELECT '1' FROM (SELECT patient_ref AS patient_id, resource FROM resources WHERE resourceType = 'Claim') AS _c WHERE _c.patient_id = AdultEDEncounters.patient_id AND fhirpath_text(_c.resource, 'status') = 'active' AND fhirpath_text(_c.resource, 'use') = 'claim' AND claim_principal_diagnosis(_c.resource, fhirpath_text(AdultEDEncounters.resource, 'id')) IS NOT NULL AND (in_valueset(claim_principal_diagnosis(_c.resource, fhirpath_text(AdultEDEncounters.resource, 'id')), 'diagnosisCodeableConcept', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1046.285') OR EXISTS (SELECT '1' FROM (SELECT patient_ref AS patient_id, resource FROM resources WHERE resourceType = 'Condition') AS _cond WHERE _cond.patient_id = AdultEDEncounters.patient_id AND in_valueset(_cond.resource, 'code', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1046.285') AND fhirpath_text(claim_principal_diagnosis(_c.resource, fhirpath_text(AdultEDEncounters.resource, 'id')), 'diagnosisReference.reference') LIKE '%/' || fhirpath_text(_cond.resource, 'id'))))
),
"ED Encounter or Triage of Patients Less Than 18 Years" AS (
SELECT * FROM "Denominator" AS EDEncounter WHERE EXTRACT(YEAR FROM CAST('2027-01-01T00:00:00.000' AS TIMESTAMP)) - EXTRACT(YEAR FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = EDEncounter.patient_id LIMIT 1)) - CASE WHEN EXTRACT(MONTH FROM CAST('2027-01-01T00:00:00.000' AS TIMESTAMP)) < EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = EDEncounter.patient_id LIMIT 1)) OR EXTRACT(MONTH FROM CAST('2027-01-01T00:00:00.000' AS TIMESTAMP)) = EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = EDEncounter.patient_id LIMIT 1)) AND EXTRACT(DAY FROM CAST('2027-01-01T00:00:00.000' AS TIMESTAMP)) < EXTRACT(DAY FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = EDEncounter.patient_id LIMIT 1)) THEN 1 ELSE 0 END < 18
),
"ED Observation Status" AS (
SELECT * FROM "Encounter: Observation Services" AS EDObsEncounter WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "Denominator") AS EDEncounter WHERE intervalIncludes(fhirpath_text(EDEncounter.resource, 'period'), fhirpath_text(EDObsEncounter.resource, 'period')) AND fhirpath_text(EDObsEncounter.resource, 'status') = 'finished' AND EDEncounter.patient_id = EDObsEncounter.patient_id)
),
"ED Triage Before Evaluation Management" AS (
SELECT * FROM "ED Triage" AS EDTriageinMP WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "Denominator") AS EDEncounter WHERE (intervalOverlapsBefore(fhirpath_text(EDTriageinMP.resource, 'period'), fhirpath_text(EDEncounter.resource, 'period')) OR intervalIncludes(fhirpath_text(EDEncounter.resource, 'period'), fhirpath_text(EDTriageinMP.resource, 'period')) OR intervalIncludes(fhirpath_text(EDTriageinMP.resource, 'period'), fhirpath_text(EDEncounter.resource, 'period')) OR CAST(intervalStart(fhirpath_text(EDEncounter.resource, 'period')) AS TIMESTAMP) - INTERVAL '120 minute' <= CAST(intervalEnd(fhirpath_text(EDTriageinMP.resource, 'period')) AS TIMESTAMP) AND CAST(intervalEnd(fhirpath_text(EDTriageinMP.resource, 'period')) AS TIMESTAMP) < CAST(intervalStart(fhirpath_text(EDEncounter.resource, 'period')) AS TIMESTAMP)) AND EDEncounter.patient_id = EDTriageinMP.patient_id)
),
"ED Triage and Evaluation Management" AS (
(SELECT patient_id, resource FROM "Denominator") UNION (SELECT patient_id, resource FROM "ED Triage Before Evaluation Management")
),
"Admitted to Inpatient 241 Minutes or More Before Departure" AS (
SELECT * FROM "Denominator" AS EDEncounter WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "CQMCommon.Inpatient Encounter") AS Inpatient WHERE CAST((SELECT intervalStart(fhirpath_text(AdmittedInpatient.resource, 'period')) FROM "CQMCommon.Inpatient Encounter" AS AdmittedInpatient WHERE intervalContains(fhirpath_text((SELECT resource FROM "ED Evaluation and Management" AS EDEvalManagementInMP WHERE CAST(intervalStart(fhirpath_text(Inpatient.resource, 'period')) AS TIMESTAMP) - INTERVAL '1 day' <= CAST(intervalStart(fhirpath_text(EDEvalManagementInMP.resource, 'period')) AS TIMESTAMP) AND CAST(intervalStart(fhirpath_text(EDEvalManagementInMP.resource, 'period')) AS TIMESTAMP) <= CAST(intervalStart(fhirpath_text(Inpatient.resource, 'period')) AS TIMESTAMP) AND CAST(intervalStart(fhirpath_text(EDEvalManagementInMP.resource, 'period')) AS TIMESTAMP) < CAST(intervalStart(fhirpath_text(Inpatient.resource, 'period')) AS TIMESTAMP) AND CAST(intervalStart(fhirpath_text(EDEvalManagementInMP.resource, 'period')) AS DATE) >= CAST(CAST('2027-01-01T00:00:00.000' AS TIMESTAMP) AS DATE) AND CAST(intervalEnd(fhirpath_text(EDEvalManagementInMP.resource, 'period')) AS DATE) <= CAST(CAST('2027-12-31T23:59:59.999' AS TIMESTAMP) AS DATE) AND fhirpath_text(EDEvalManagementInMP.resource, 'status') = 'finished' AND EDEvalManagementInMP.patient_id = EDEncounter.patient_id ORDER BY intervalEnd(fhirpath_text(EDEvalManagementInMP.resource, 'period')) DESC NULLS FIRST, json_extract_string(EDEvalManagementInMP.resource, '$.id') ASC NULLS LAST LIMIT 1), 'period'), intervalStart(fhirpath_text(AdmittedInpatient.resource, 'period'))) AND AdmittedInpatient.patient_id = EDEncounter.patient_id ORDER BY intervalStart(fhirpath_text(AdmittedInpatient.resource, 'period')) DESC NULLS FIRST, json_extract_string(AdmittedInpatient.resource, '$.id') ASC NULLS LAST LIMIT 1) AS TIMESTAMP) <= CAST(list_extract(list_sort((SELECT list(intervalEnd(fhirpath_text(_lt_Location, 'period'))) FROM (SELECT unnest(from_json(fhirpath(_bb_Location.resource, 'location'), '["VARCHAR"]')) AS _lt_Location FROM "ED Triage and Evaluation Management" AS _bb_Location WHERE _bb_Location.patient_id = Inpatient.patient_id) AS _bb_unnest WHERE in_valueset(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_Location, 'location.reference'), '/'), -1) AND L.patient_id = Inpatient.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_Location, 'location.reference'), '/'), -1) AND L.patient_id = Inpatient.patient_id LIMIT 1) ELSE NULL END, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1046.284') AND intervalEnd(fhirpath_text(_lt_Location, 'period')) IS NOT NULL AND (CAST(intervalStart(fhirpath_text(EDEncounter.resource, 'period')) AS TIMESTAMP) - INTERVAL '120 minute' <= CAST(intervalEnd(fhirpath_text(_lt_Location, 'period')) AS TIMESTAMP) AND CAST(intervalEnd(fhirpath_text(_lt_Location, 'period')) AS TIMESTAMP) < CAST(intervalStart(fhirpath_text(EDEncounter.resource, 'period')) AS TIMESTAMP) OR intervalOverlapsBefore(fhirpath_text(_lt_Location, 'period'), fhirpath_text(EDEncounter.resource, 'period')) OR intervalOverlapsBefore(fhirpath_text(EDEncounter.resource, 'period'), fhirpath_text(_lt_Location, 'period')) OR CAST(intervalStart(fhirpath_text(_lt_Location, 'period')) AS DATE) = CAST(intervalStart(fhirpath_text(EDEncounter.resource, 'period')) AS DATE))), 'asc'), -1) AS TIMESTAMP) - INTERVAL '241 minute' AND Inpatient.patient_id = EDEncounter.patient_id)
),
"Decision to Admit Encounter Order" AS (
SELECT * FROM "Denominator" AS EDEncounter WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "CQMCommon.Inpatient Encounter") AS EncounterInpatient WHERE CAST((SELECT fhirpath_text(AdmitOrder.resource, 'authoredOn') FROM "ED To Inpatient Order" AS AdmitOrder WHERE intervalContains(fhirpath_text((SELECT resource FROM "ED Evaluation and Management" AS EDEvalManagementInMP WHERE CAST(intervalStart(fhirpath_text(EncounterInpatient.resource, 'period')) AS TIMESTAMP) - INTERVAL '1 day' <= CAST(intervalStart(fhirpath_text(EDEvalManagementInMP.resource, 'period')) AS TIMESTAMP) AND CAST(intervalStart(fhirpath_text(EDEvalManagementInMP.resource, 'period')) AS TIMESTAMP) <= CAST(intervalStart(fhirpath_text(EncounterInpatient.resource, 'period')) AS TIMESTAMP) AND CAST(intervalStart(fhirpath_text(EDEvalManagementInMP.resource, 'period')) AS TIMESTAMP) < CAST(intervalStart(fhirpath_text(EncounterInpatient.resource, 'period')) AS TIMESTAMP) AND CAST(intervalStart(fhirpath_text(EDEvalManagementInMP.resource, 'period')) AS DATE) >= CAST(CAST('2027-01-01T00:00:00.000' AS TIMESTAMP) AS DATE) AND CAST(intervalEnd(fhirpath_text(EDEvalManagementInMP.resource, 'period')) AS DATE) <= CAST(CAST('2027-12-31T23:59:59.999' AS TIMESTAMP) AS DATE) AND fhirpath_text(EDEvalManagementInMP.resource, 'status') = 'finished' AND EDEvalManagementInMP.patient_id = EDEncounter.patient_id ORDER BY intervalEnd(fhirpath_text(EDEvalManagementInMP.resource, 'period')) DESC NULLS FIRST, json_extract_string(EDEvalManagementInMP.resource, '$.id') ASC NULLS LAST LIMIT 1), 'period'), fhirpath_text(AdmitOrder.resource, 'authoredOn')) AND CASE WHEN fhirpath_text(AdmitOrder.resource, 'intent') IS NULL AND 'order' IS NULL THEN TRUE WHEN fhirpath_text(AdmitOrder.resource, 'intent') IS NULL OR 'order' IS NULL THEN FALSE ELSE fhirpath_text(AdmitOrder.resource, 'intent') = 'order' END AND AdmitOrder.patient_id = EDEncounter.patient_id ORDER BY fhirpath_text(AdmitOrder.resource, 'authoredOn') DESC NULLS FIRST, json_extract_string(AdmitOrder.resource, '$.id') ASC NULLS LAST LIMIT 1) AS TIMESTAMP) <= CAST(list_extract(list_sort((SELECT list(intervalEnd(fhirpath_text(_lt_Location, 'period'))) FROM (SELECT unnest(from_json(fhirpath(_bb_Location.resource, 'location'), '["VARCHAR"]')) AS _lt_Location FROM "ED Triage and Evaluation Management" AS _bb_Location WHERE _bb_Location.patient_id = EncounterInpatient.patient_id) AS _bb_unnest WHERE in_valueset(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_Location, 'location.reference'), '/'), -1) AND L.patient_id = EncounterInpatient.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_Location, 'location.reference'), '/'), -1) AND L.patient_id = EncounterInpatient.patient_id LIMIT 1) ELSE NULL END, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1046.284') AND intervalEnd(fhirpath_text(_lt_Location, 'period')) IS NOT NULL AND (CAST(intervalStart(fhirpath_text(EDEncounter.resource, 'period')) AS TIMESTAMP) - INTERVAL '120 minute' <= CAST(intervalEnd(fhirpath_text(_lt_Location, 'period')) AS TIMESTAMP) AND CAST(intervalEnd(fhirpath_text(_lt_Location, 'period')) AS TIMESTAMP) < CAST(intervalStart(fhirpath_text(EDEncounter.resource, 'period')) AS TIMESTAMP) OR intervalOverlapsBefore(fhirpath_text(_lt_Location, 'period'), fhirpath_text(EDEncounter.resource, 'period')) OR intervalOverlapsBefore(fhirpath_text(EDEncounter.resource, 'period'), fhirpath_text(_lt_Location, 'period')) OR CAST(intervalStart(fhirpath_text(_lt_Location, 'period')) AS DATE) = CAST(intervalStart(fhirpath_text(EDEncounter.resource, 'period')) AS DATE))), 'asc'), -1) AS TIMESTAMP) - INTERVAL '241 minute' AND EncounterInpatient.patient_id = EDEncounter.patient_id)
),
"Decision to Admit Using Assessment" AS (
SELECT * FROM "Denominator" AS EDEncounter WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "CQMCommon.Inpatient Encounter") AS EncounterInpatient WHERE CAST((SELECT intervalStart(CASE WHEN fhirpath_text(EDEvaluation.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(EDEvaluation.resource, 'effective')), '{') THEN fhirpath_text(EDEvaluation.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(EDEvaluation.resource, 'effective'), fhirpath_text(EDEvaluation.resource, 'effective'), TRUE, TRUE) END) FROM "Assessment In ED" AS EDEvaluation WHERE intervalContains(fhirpath_text((SELECT resource FROM "ED Evaluation and Management" AS EDEvalManagementInMP WHERE CAST(intervalStart(fhirpath_text(EncounterInpatient.resource, 'period')) AS TIMESTAMP) - INTERVAL '1 day' <= CAST(intervalStart(fhirpath_text(EDEvalManagementInMP.resource, 'period')) AS TIMESTAMP) AND CAST(intervalStart(fhirpath_text(EDEvalManagementInMP.resource, 'period')) AS TIMESTAMP) <= CAST(intervalStart(fhirpath_text(EncounterInpatient.resource, 'period')) AS TIMESTAMP) AND CAST(intervalStart(fhirpath_text(EDEvalManagementInMP.resource, 'period')) AS TIMESTAMP) < CAST(intervalStart(fhirpath_text(EncounterInpatient.resource, 'period')) AS TIMESTAMP) AND CAST(intervalStart(fhirpath_text(EDEvalManagementInMP.resource, 'period')) AS DATE) >= CAST(CAST('2027-01-01T00:00:00.000' AS TIMESTAMP) AS DATE) AND CAST(intervalEnd(fhirpath_text(EDEvalManagementInMP.resource, 'period')) AS DATE) <= CAST(CAST('2027-12-31T23:59:59.999' AS TIMESTAMP) AS DATE) AND fhirpath_text(EDEvalManagementInMP.resource, 'status') = 'finished' AND EDEvalManagementInMP.patient_id = EDEncounter.patient_id ORDER BY intervalEnd(fhirpath_text(EDEvalManagementInMP.resource, 'period')) DESC NULLS FIRST, json_extract_string(EDEvalManagementInMP.resource, '$.id') ASC NULLS LAST LIMIT 1), 'period'), intervalStart(CASE WHEN fhirpath_text(EDEvaluation.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(EDEvaluation.resource, 'effective')), '{') THEN fhirpath_text(EDEvaluation.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(EDEvaluation.resource, 'effective'), fhirpath_text(EDEvaluation.resource, 'effective'), TRUE, TRUE) END)) AND array_contains(['final', 'amended', 'corrected'], fhirpath_text(EDEvaluation.resource, 'status')) AND EDEvaluation.patient_id = EDEncounter.patient_id ORDER BY intervalStart(CASE WHEN fhirpath_text(EDEvaluation.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(EDEvaluation.resource, 'effective')), '{') THEN fhirpath_text(EDEvaluation.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(EDEvaluation.resource, 'effective'), fhirpath_text(EDEvaluation.resource, 'effective'), TRUE, TRUE) END) DESC NULLS FIRST, json_extract_string(EDEvaluation.resource, '$.id') ASC NULLS LAST LIMIT 1) AS TIMESTAMP) <= CAST(list_extract(list_sort((SELECT list(intervalEnd(fhirpath_text(_lt_Location, 'period'))) FROM (SELECT unnest(from_json(fhirpath(_bb_Location.resource, 'location'), '["VARCHAR"]')) AS _lt_Location FROM "ED Triage and Evaluation Management" AS _bb_Location WHERE _bb_Location.patient_id = EncounterInpatient.patient_id) AS _bb_unnest WHERE in_valueset(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_Location, 'location.reference'), '/'), -1) AND L.patient_id = EncounterInpatient.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_Location, 'location.reference'), '/'), -1) AND L.patient_id = EncounterInpatient.patient_id LIMIT 1) ELSE NULL END, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1046.284') AND intervalEnd(fhirpath_text(_lt_Location, 'period')) IS NOT NULL AND (CAST(intervalStart(fhirpath_text(EDEncounter.resource, 'period')) AS TIMESTAMP) - INTERVAL '120 minute' <= CAST(intervalEnd(fhirpath_text(_lt_Location, 'period')) AS TIMESTAMP) AND CAST(intervalEnd(fhirpath_text(_lt_Location, 'period')) AS TIMESTAMP) < CAST(intervalStart(fhirpath_text(EDEncounter.resource, 'period')) AS TIMESTAMP) OR intervalOverlapsBefore(fhirpath_text(_lt_Location, 'period'), fhirpath_text(EDEncounter.resource, 'period')) OR intervalOverlapsBefore(fhirpath_text(EDEncounter.resource, 'period'), fhirpath_text(_lt_Location, 'period')) OR CAST(intervalStart(fhirpath_text(_lt_Location, 'period')) AS DATE) = CAST(intervalStart(fhirpath_text(EDEncounter.resource, 'period')) AS DATE))), 'asc'), -1) AS TIMESTAMP) - INTERVAL '241 minute' AND EncounterInpatient.patient_id = EDEncounter.patient_id)
),
"ED Length of Stay Greater Than 480 Minutes" AS (
SELECT * FROM "Denominator" AS EDEncounter WHERE CAST(list_extract(list_sort((SELECT list(intervalStart(fhirpath_text(_lt_Location, 'period'))) FROM (SELECT unnest(from_json(fhirpath(_bb_Location.resource, 'location'), '["VARCHAR"]')) AS _lt_Location FROM "ED Triage and Evaluation Management" AS _bb_Location WHERE _bb_Location.patient_id = EDEncounter.patient_id) AS _bb_unnest WHERE in_valueset(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_Location, 'location.reference'), '/'), -1) AND L.patient_id = EDEncounter.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_Location, 'location.reference'), '/'), -1) AND L.patient_id = EDEncounter.patient_id LIMIT 1) ELSE NULL END, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1046.284') AND intervalStart(fhirpath_text(_lt_Location, 'period')) IS NOT NULL AND (CAST(intervalStart(fhirpath_text(EDEncounter.resource, 'period')) AS TIMESTAMP) - INTERVAL '120 minute' <= CAST(intervalEnd(fhirpath_text(_lt_Location, 'period')) AS TIMESTAMP) AND CAST(intervalEnd(fhirpath_text(_lt_Location, 'period')) AS TIMESTAMP) < CAST(intervalStart(fhirpath_text(EDEncounter.resource, 'period')) AS TIMESTAMP) OR intervalOverlapsBefore(fhirpath_text(_lt_Location, 'period'), fhirpath_text(EDEncounter.resource, 'period')) OR intervalOverlapsBefore(fhirpath_text(EDEncounter.resource, 'period'), fhirpath_text(_lt_Location, 'period')) OR CAST(intervalStart(fhirpath_text(_lt_Location, 'period')) AS DATE) = CAST(intervalStart(fhirpath_text(EDEncounter.resource, 'period')) AS DATE))), 'asc'), -1) AS TIMESTAMP) <= CAST(list_extract(list_sort((SELECT list(intervalEnd(fhirpath_text(_lt_Location, 'period'))) FROM (SELECT unnest(from_json(fhirpath(_bb_Location.resource, 'location'), '["VARCHAR"]')) AS _lt_Location FROM "ED Triage and Evaluation Management" AS _bb_Location WHERE _bb_Location.patient_id = EDEncounter.patient_id) AS _bb_unnest WHERE in_valueset(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_Location, 'location.reference'), '/'), -1) AND L.patient_id = EDEncounter.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_Location, 'location.reference'), '/'), -1) AND L.patient_id = EDEncounter.patient_id LIMIT 1) ELSE NULL END, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1046.284') AND intervalEnd(fhirpath_text(_lt_Location, 'period')) IS NOT NULL AND (CAST(intervalStart(fhirpath_text(EDEncounter.resource, 'period')) AS TIMESTAMP) - INTERVAL '120 minute' <= CAST(intervalEnd(fhirpath_text(_lt_Location, 'period')) AS TIMESTAMP) AND CAST(intervalEnd(fhirpath_text(_lt_Location, 'period')) AS TIMESTAMP) < CAST(intervalStart(fhirpath_text(EDEncounter.resource, 'period')) AS TIMESTAMP) OR intervalOverlapsBefore(fhirpath_text(_lt_Location, 'period'), fhirpath_text(EDEncounter.resource, 'period')) OR intervalOverlapsBefore(fhirpath_text(EDEncounter.resource, 'period'), fhirpath_text(_lt_Location, 'period')) OR CAST(intervalStart(fhirpath_text(_lt_Location, 'period')) AS DATE) = CAST(intervalStart(fhirpath_text(EDEncounter.resource, 'period')) AS DATE))), 'asc'), -1) AS TIMESTAMP) - INTERVAL '481 minute'
),
"ED Length of Stay Greater Than 480 Minutes and No Observation Stay" AS (
SELECT * FROM "ED Length of Stay Greater Than 480 Minutes" AS EDStay WHERE NOT EXISTS (SELECT * FROM "ED Observation Status" AS EDObs WHERE intervalIncludes(fhirpath_text(EDStay.resource, 'period'), fhirpath_text(EDObs.resource, 'period')) AND EDObs.patient_id = EDStay.patient_id)
),
"Inpatient Or Bed Assignment Encounter Order" AS (
SELECT * FROM (SELECT patient_id, resource FROM "ServiceRequest: Encounter Inpatient" UNION SELECT patient_id, resource FROM "ServiceRequest: Patient bed assigned (finding)") AS IPRequest WHERE array_contains(['active', 'completed'], fhirpath_text(IPRequest.resource, 'status'))
),
"Pediatric With Mental Health Diagnosis" AS (
SELECT * FROM "ED Encounter or Triage of Patients Less Than 18 Years" AS PediatricEDEncounters WHERE EXISTS (SELECT '1' FROM (SELECT patient_ref AS patient_id, resource FROM resources WHERE resourceType = 'Claim') AS _c WHERE _c.patient_id = PediatricEDEncounters.patient_id AND fhirpath_text(_c.resource, 'status') = 'active' AND fhirpath_text(_c.resource, 'use') = 'claim' AND claim_principal_diagnosis(_c.resource, fhirpath_text(PediatricEDEncounters.resource, 'id')) IS NOT NULL AND (in_valueset(claim_principal_diagnosis(_c.resource, fhirpath_text(PediatricEDEncounters.resource, 'id')), 'diagnosisCodeableConcept', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1046.285') OR EXISTS (SELECT '1' FROM (SELECT patient_ref AS patient_id, resource FROM resources WHERE resourceType = 'Condition') AS _cond WHERE _cond.patient_id = PediatricEDEncounters.patient_id AND in_valueset(_cond.resource, 'code', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1046.285') AND fhirpath_text(claim_principal_diagnosis(_c.resource, fhirpath_text(PediatricEDEncounters.resource, 'id')), 'diagnosisReference.reference') LIKE '%/' || fhirpath_text(_cond.resource, 'id'))))
),
"Pediatric With No Mental Health Diagnosis" AS (
SELECT * FROM "ED Encounter or Triage of Patients Less Than 18 Years" AS PediatricEDEncounters WHERE NOT EXISTS (SELECT '1' FROM (SELECT patient_ref AS patient_id, resource FROM resources WHERE resourceType = 'Claim') AS _c WHERE _c.patient_id = PediatricEDEncounters.patient_id AND fhirpath_text(_c.resource, 'status') = 'active' AND fhirpath_text(_c.resource, 'use') = 'claim' AND claim_principal_diagnosis(_c.resource, fhirpath_text(PediatricEDEncounters.resource, 'id')) IS NOT NULL AND (in_valueset(claim_principal_diagnosis(_c.resource, fhirpath_text(PediatricEDEncounters.resource, 'id')), 'diagnosisCodeableConcept', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1046.285') OR EXISTS (SELECT '1' FROM (SELECT patient_ref AS patient_id, resource FROM resources WHERE resourceType = 'Condition') AS _cond WHERE _cond.patient_id = PediatricEDEncounters.patient_id AND in_valueset(_cond.resource, 'code', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1046.285') AND fhirpath_text(claim_principal_diagnosis(_c.resource, fhirpath_text(PediatricEDEncounters.resource, 'id')), 'diagnosisReference.reference') LIKE '%/' || fhirpath_text(_cond.resource, 'id'))))
),
