"Time of Admit Order Or Bed Assignment to Departure Greater Than 241 Minutes" AS (
SELECT * FROM "Denominator" AS EDEncounter WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "CQMCommon.Inpatient Encounter") AS InpatientEncounter WHERE CAST((SELECT fhirpath_text(AdmitInpatientOrder.resource, 'authoredOn') FROM "Inpatient Or Bed Assignment Encounter Order" AS AdmitInpatientOrder WHERE intervalContains(fhirpath_text((SELECT resource FROM "ED Evaluation and Management" AS EDEvalManagementInMP WHERE CAST(intervalStart(fhirpath_text(InpatientEncounter.resource, 'period')) AS TIMESTAMP) - INTERVAL '1 day' <= CAST(intervalStart(fhirpath_text(EDEvalManagementInMP.resource, 'period')) AS TIMESTAMP) AND CAST(intervalStart(fhirpath_text(EDEvalManagementInMP.resource, 'period')) AS TIMESTAMP) <= CAST(intervalStart(fhirpath_text(InpatientEncounter.resource, 'period')) AS TIMESTAMP) AND CAST(intervalStart(fhirpath_text(EDEvalManagementInMP.resource, 'period')) AS TIMESTAMP) < CAST(intervalStart(fhirpath_text(InpatientEncounter.resource, 'period')) AS TIMESTAMP) AND CAST(intervalStart(fhirpath_text(EDEvalManagementInMP.resource, 'period')) AS DATE) >= CAST(CAST('2027-01-01T00:00:00.000' AS TIMESTAMP) AS DATE) AND CAST(intervalEnd(fhirpath_text(EDEvalManagementInMP.resource, 'period')) AS DATE) <= CAST(CAST('2027-12-31T23:59:59.999' AS TIMESTAMP) AS DATE) AND fhirpath_text(EDEvalManagementInMP.resource, 'status') = 'finished' AND EDEvalManagementInMP.patient_id = EDEncounter.patient_id ORDER BY intervalEnd(fhirpath_text(EDEvalManagementInMP.resource, 'period')) DESC NULLS FIRST, json_extract_string(EDEvalManagementInMP.resource, '$.id') ASC NULLS LAST LIMIT 1), 'period'), fhirpath_text(AdmitInpatientOrder.resource, 'authoredOn')) AND AdmitInpatientOrder.patient_id = EDEncounter.patient_id ORDER BY fhirpath_text(AdmitInpatientOrder.resource, 'authoredOn') DESC NULLS FIRST, json_extract_string(AdmitInpatientOrder.resource, '$.id') ASC NULLS LAST LIMIT 1) AS TIMESTAMP) <= CAST(list_extract(list_sort((SELECT list(intervalEnd(fhirpath_text(_lt_Location, 'period'))) FROM (SELECT unnest(from_json(fhirpath(_bb_Location.resource, 'location'), '["VARCHAR"]')) AS _lt_Location FROM "ED Triage and Evaluation Management" AS _bb_Location WHERE _bb_Location.patient_id = InpatientEncounter.patient_id) AS _bb_unnest WHERE in_valueset(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_Location, 'location.reference'), '/'), -1) AND L.patient_id = InpatientEncounter.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_Location, 'location.reference'), '/'), -1) AND L.patient_id = InpatientEncounter.patient_id LIMIT 1) ELSE NULL END, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1046.284') AND intervalEnd(fhirpath_text(_lt_Location, 'period')) IS NOT NULL AND (CAST(intervalStart(fhirpath_text(EDEncounter.resource, 'period')) AS TIMESTAMP) - INTERVAL '120 minute' <= CAST(intervalEnd(fhirpath_text(_lt_Location, 'period')) AS TIMESTAMP) AND CAST(intervalEnd(fhirpath_text(_lt_Location, 'period')) AS TIMESTAMP) < CAST(intervalStart(fhirpath_text(EDEncounter.resource, 'period')) AS TIMESTAMP) OR intervalOverlapsBefore(fhirpath_text(_lt_Location, 'period'), fhirpath_text(EDEncounter.resource, 'period')) OR intervalOverlapsBefore(fhirpath_text(EDEncounter.resource, 'period'), fhirpath_text(_lt_Location, 'period')) OR CAST(intervalStart(fhirpath_text(_lt_Location, 'period')) AS DATE) = CAST(intervalStart(fhirpath_text(EDEncounter.resource, 'period')) AS DATE))), 'asc'), -1) AS TIMESTAMP) - INTERVAL '241 minute' AND InpatientEncounter.patient_id = EDEncounter.patient_id)
),
"Boarded Time Greater Than 240 Minutes" AS (
(SELECT patient_id, resource FROM "Decision to Admit Encounter Order") UNION (SELECT patient_id, resource FROM "Decision to Admit Using Assessment") UNION (SELECT patient_id, resource FROM "Time of Admit Order Or Bed Assignment to Departure Greater Than 241 Minutes") UNION (SELECT patient_id, resource FROM "Admitted to Inpatient 241 Minutes or More Before Departure")
),
"Boarded Time Greater Than 240 Minutes and No Observation Stay" AS (
SELECT * FROM "Boarded Time Greater Than 240 Minutes" AS Boarding WHERE NOT EXISTS (SELECT * FROM "ED Observation Status" AS EDO WHERE intervalIncludes(fhirpath_text(Boarding.resource, 'period'), fhirpath_text(EDO.resource, 'period')) AND EDO.patient_id = Boarding.patient_id)
),
"Time to Treatment Room Greater Than 60 Minutes" AS (
SELECT * FROM "ED Evaluation and Management" AS EDEvalManagementInMP WHERE CAST(list_extract(list_sort((SELECT list(intervalStart(fhirpath_text(_lt_Location, 'period'))) FROM (SELECT unnest(from_json(fhirpath(_bb_Location.resource, 'location'), '["VARCHAR"]')) AS _lt_Location FROM "ED Triage and Evaluation Management" AS _bb_Location WHERE _bb_Location.patient_id = EDEvalManagementInMP.patient_id) AS _bb_unnest WHERE in_valueset(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_Location, 'location.reference'), '/'), -1) AND L.patient_id = EDEvalManagementInMP.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_Location, 'location.reference'), '/'), -1) AND L.patient_id = EDEvalManagementInMP.patient_id LIMIT 1) ELSE NULL END, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1046.284') AND intervalStart(fhirpath_text(_lt_Location, 'period')) IS NOT NULL AND (CAST(intervalStart(fhirpath_text(EDEvalManagementInMP.resource, 'period')) AS TIMESTAMP) - INTERVAL '120 minute' <= CAST(intervalEnd(fhirpath_text(_lt_Location, 'period')) AS TIMESTAMP) AND CAST(intervalEnd(fhirpath_text(_lt_Location, 'period')) AS TIMESTAMP) < CAST(intervalStart(fhirpath_text(EDEvalManagementInMP.resource, 'period')) AS TIMESTAMP) OR intervalOverlapsBefore(fhirpath_text(_lt_Location, 'period'), fhirpath_text(EDEvalManagementInMP.resource, 'period')) OR intervalOverlapsBefore(fhirpath_text(EDEvalManagementInMP.resource, 'period'), fhirpath_text(_lt_Location, 'period')) OR CAST(intervalStart(fhirpath_text(_lt_Location, 'period')) AS DATE) = CAST(intervalStart(fhirpath_text(EDEvalManagementInMP.resource, 'period')) AS DATE))), 'asc'), -1) AS TIMESTAMP) <= CAST(list_extract(list_sort((SELECT list(intervalStart(fhirpath_text(_lt_Location, 'period'))) FROM (SELECT unnest(from_json(fhirpath(EDEvalManagementInMP.resource, 'location'), '["VARCHAR"]')) AS _lt_Location) AS _lt_unnest WHERE in_valueset(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_Location, 'location.reference'), '/'), -1) AND L.patient_id = EDEvalManagementInMP.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_Location, 'location.reference'), '/'), -1) AND L.patient_id = EDEvalManagementInMP.patient_id LIMIT 1) ELSE NULL END, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1046.278') AND intervalStart(fhirpath_text(_lt_Location, 'period')) IS NOT NULL), 'asc'), 1) AS TIMESTAMP) - INTERVAL '61 minute'
),
"Numerator" AS (
(SELECT patient_id, resource FROM "Time to Treatment Room Greater Than 60 Minutes") UNION (SELECT patient_id, resource FROM "ED Arrival Left Without Being Seen") UNION (SELECT patient_id, resource FROM "Boarded Time Greater Than 240 Minutes and No Observation Stay") UNION (SELECT patient_id, resource FROM "ED Length of Stay Greater Than 480 Minutes and No Observation Stay")
)
SELECT p.patient_id, (SELECT COALESCE(LIST(json_extract_string("Initial Population".resource, '$.resourceType') || '/' || json_extract_string("Initial Population".resource, '$.id')), []) FROM "Initial Population" WHERE "Initial Population".patient_id = p.patient_id AND "Initial Population".resource IS NOT NULL) AS "Initial Population", (SELECT COALESCE(LIST(json_extract_string("Denominator".resource, '$.resourceType') || '/' || json_extract_string("Denominator".resource, '$.id')), []) FROM "Denominator" WHERE "Denominator".patient_id = p.patient_id AND "Denominator".resource IS NOT NULL) AS Denominator, (SELECT COALESCE(LIST(json_extract_string("Numerator".resource, '$.resourceType') || '/' || json_extract_string("Numerator".resource, '$.id')), []) FROM "Numerator" WHERE "Numerator".patient_id = p.patient_id AND "Numerator".resource IS NOT NULL) AS Numerator FROM _patients p ORDER BY p.patient_id ASC
